import json, sys, ssl, base64, urllib.request, urllib.parse, urllib.error

def load_connector_config(path="/run/connector.json"):
    try:
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception as e:
        err("Failed to load /run/connector.json", {"exception": str(e)})


def err(msg, details=None, code=1):
    out = {"ok": False, "error": str(msg)}
    if details is not None:
        out["details"] = details
    print(json.dumps(out, ensure_ascii=False))
    sys.exit(code)


def build_jql(cfg):
    raw = (cfg.get("jql") or "").strip()
    if raw:
        return raw
    parts = []
    assignee_key_type = (cfg.get("assigneeKeyType") or "accountId").strip()
    if assignee_key_type == "currentUser":
        parts.append("assignee = currentUser()")
    else:
        assignee = cfg.get("assignee")
        if not assignee:
            err("Missing configuration.assignee when assigneeKeyType is not 'currentUser' and no raw jql is provided")
        val = str(assignee)
        val_escaped = val.replace("\"", "\\\"")
        parts.append(f"assignee = \"{val_escaped}\"")
    project_key = cfg.get("projectKey")
    if project_key:
        p_escaped = str(project_key).replace("\"", "\\\"")
        parts.append(f"project = \"{p_escaped}\"")
    statuses = cfg.get("statuses") or []
    if isinstance(statuses, list) and statuses:
        quoted = ", ".join([f"\"{str(s).replace('\"','\\\"')}\"" for s in statuses])
        parts.append(f"status in ({quoted})")
    updated_since_days = cfg.get("updatedSinceDays")
    if isinstance(updated_since_days, int) and updated_since_days > 0:
        parts.append(f"updated >= -{updated_since_days}d")
    jql = " AND ".join(parts) if parts else ""
    order_by = (cfg.get("orderBy") or "").strip()
    if order_by:
        jql = f"{jql} ORDER BY {order_by}" if jql else f"ORDER BY {order_by}"
    if not jql:
        err("Could not construct JQL: provide configuration.jql or enough parameters to build one (e.g., assignee or currentUser)")
    return jql


def simplify_issue(issue, base_url):
    f = issue.get("fields", {}) or {}
    status = f.get("status") or {}
    assignee = f.get("assignee") or {}
    project = f.get("project") or {}
    issuetype = f.get("issuetype") or {}
    priority = f.get("priority") or {}
    key = issue.get("key")
    return {
        "id": issue.get("id"),
        "key": key,
        "url": (base_url.rstrip("/") + "/browse/" + key) if (base_url and key) else None,
        "summary": f.get("summary"),
        "status": {"name": status.get("name"), "id": status.get("id"), "category": (status.get("statusCategory") or {}).get("name")},
        "assignee": {"displayName": assignee.get("displayName"), "accountId": assignee.get("accountId"), "emailAddress": assignee.get("emailAddress")},
        "priority": {"name": priority.get("name"), "id": priority.get("id")},
        "project": {"key": project.get("key"), "id": project.get("id"), "name": project.get("name")},
        "issueType": {"name": issuetype.get("name"), "id": issuetype.get("id")},
        "created": f.get("created"),
        "updated": f.get("updated"),
        "dueDate": f.get("duedate"),
        "labels": f.get("labels")
    }


def _basic_auth_header(email, token):
    token_str = f"{email}:{token}".encode("utf-8")
    b64 = base64.b64encode(token_str).decode("ascii")
    return f"Basic {b64}"


def _http_request(url, method="GET", params=None, headers=None, timeout=60, verify_ssl=True, json_body=None):
    full_url = url
    if params:
        query = urllib.parse.urlencode(params, doseq=True)
        sep = '&' if urllib.parse.urlparse(url).query else '?'
        full_url = f"{url}{sep}{query}"
    data_bytes = None
    req_headers = {}
    if headers:
        req_headers.update(headers)
    if json_body is not None:
        try:
            data_bytes = json.dumps(json_body).encode("utf-8")
        except Exception as e:
            raise RuntimeError(f"Failed to encode JSON body: {e}")
        # Ensure content-type
        if not any(k.lower() == "content-type" for k in req_headers):
            req_headers["Content-Type"] = "application/json"
    req = urllib.request.Request(full_url, data=data_bytes, method=method)
    for k, v in req_headers.items():
        req.add_header(k, v)
    context = None
    if verify_ssl is False:
        context = ssl.create_default_context()
        context.check_hostname = False
        context.verify_mode = ssl.CERT_NONE
    try:
        with urllib.request.urlopen(req, timeout=timeout, context=context) as resp:
            status = resp.getcode()
            body = resp.read()
            text = body.decode("utf-8", errors="replace")
            data = None
            try:
                data = json.loads(text)
            except Exception:
                data = None
            return status, data, text
    except urllib.error.HTTPError as e:
        status = e.code
        try:
            body = e.read()
        except Exception:
            body = b""
        text = body.decode("utf-8", errors="replace")
        data = None
        try:
            data = json.loads(text)
        except Exception:
            data = None
        return status, data, text
    except urllib.error.URLError as e:
        raise RuntimeError(f"Network error: {e}")


def main():
    cfg_all = load_connector_config()
    auth = cfg_all.get("auth") or {}
    cfg = cfg_all.get("configuration") or {}

    email = auth.get("email")
    token = auth.get("apiToken")
    if not email or not token:
        err("Missing auth.email or auth.apiToken. Provide Jira email and an API token.")

    base_url = (cfg.get("baseUrl") or "").strip()
    if not base_url:
        err("Missing configuration.baseUrl (e.g., https://your-domain.atlassian.net)")

    api_base = base_url.rstrip("/") + "/rest/api/3"
    verify_ssl = bool(cfg.get("verifySsl", True))

    jql = build_jql(cfg)

    page_size = cfg.get("pageSize") or 100
    try:
        page_size = int(page_size)
    except Exception:
        page_size = 100
    if page_size < 1:
        page_size = 1
    if page_size > 100:
        page_size = 100

    max_results = cfg.get("maxResults") or 1000
    try:
        max_results = int(max_results)
    except Exception:
        max_results = 1000

    # Fields handling for POST body: array of fields
    fields_cfg = cfg.get("fields")
    fields_list = None
    if isinstance(fields_cfg, list) and fields_cfg:
        fields_list = fields_cfg

    # Expand handling for POST body: array of expansions
    expand_list = []
    if bool(cfg.get("expandChangelog", False)):
        expand_list.append("changelog")

    headers = {
        "Accept": "application/json",
        "Authorization": _basic_auth_header(email, token)
    }

    start_at = 0
    collected = []
    total_from_server = None

    try:
        while True:
            if max_results >= 0 and len(collected) >= max_results:
                break
            this_limit = min(page_size, max_results - len(collected)) if max_results >= 0 else page_size

            body = {
                "jql": jql,
                "startAt": start_at,
                "maxResults": this_limit
            }
            if fields_list:
                body["fields"] = fields_list
            if expand_list:
                body["expand"] = expand_list

            status_code, data_json, data_text = _http_request(
                api_base + "/search/jql",
                method="POST",
                params=None,
                headers=headers,
                timeout=60,
                verify_ssl=verify_ssl,
                json_body=body
            )

            if status_code >= 400:
                details = data_json if data_json is not None else {"text": (data_text or "")[:1000]}
                err(f"Jira API error {status_code}", details)
            if data_json is None:
                err("Invalid JSON received from Jira", {"snippet": (data_text or "")[:500]})

            issues = data_json.get("issues", [])
            total_from_server = data_json.get("total", total_from_server)
            collected.extend(issues)

            if not issues:
                break
            start_at = start_at + len(issues)
            if total_from_server is not None and start_at >= total_from_server:
                break

        include_raw = bool(cfg.get("includeRaw", False))
        simplified = [simplify_issue(it, base_url) for it in collected[: max_results if max_results >= 0 else None]]
        out = {
            "ok": True,
            "baseUrl": base_url,
            "jql": jql,
            "count": len(simplified),
            "totalReportedByJira": total_from_server,
            "data": simplified
        }
        if include_raw:
            out["issuesRaw"] = collected[: max_results if max_results >= 0 else None]
        print(json.dumps(out, ensure_ascii=False))
    except Exception as e:
        err("Unexpected error while fetching issues", {"exception": str(e)})


if __name__ == "__main__":
    main()
